import type { Collection, Folder, LocalAppCache, Space, TabItem, Workspace } from "../domain/models";
import type { LocalStoreSnapshot } from "../schemas/appSchemas";

export type AppState = {
  workspaces: Workspace[];
  workspace: Workspace | null;
  spaces: Space[];
  folders: Folder[];
  collections: Collection[];
  tabs: TabItem[];
  cache: LocalAppCache;
  rollbackStack: LocalStoreSnapshot[];
};

export const defaultCache: LocalAppCache = {
  version: 2,
  currentUserId: null,
  selectedWorkspaceId: null,
  selectedSpaceId: null,
  selectedCollectionId: null,
  expandedFolderIds: [],
  ui: {
    theme: "system",
    sidebarCollapsed: false,
    viewMode: "grid",
    sortMode: "custom",
  },
  dock: {
    pinned: [],
  },
  pendingOps: [],
  lastSyncAt: null,
  lastSyncError: null,
  nextSyncRetryAt: null,
};

export const defaultAppState: AppState = {
  workspaces: [],
  workspace: null,
  spaces: [],
  folders: [],
  collections: [],
  tabs: [],
  cache: defaultCache,
  rollbackStack: [],
};
